const input = $input.first().json;
const action = input.action || 'search_movie';

// Fetch API key from template_credentials
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.tmdb-movies&cred_key=eq.tmdb_api_key&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'TMDB API key not configured. Use add_credential to set it up.' } }];
}

const apiKey = creds[0].cred_value;
const authHeaders = {
  'Authorization': 'Bearer ' + apiKey,
  'Accept': 'application/json'
};

function formatRating(vote, count) {
  if (!vote || vote === 0) return 'No ratings yet';
  return vote.toFixed(1) + '/10 (' + count + ' votes)';
}

if (action === 'search_movie') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (movie title).' } }];
  const year = input.year || '';

  try {
    let url = 'https://api.themoviedb.org/3/search/movie?query=' + encodeURIComponent(query) + '&language=en-US&page=1';
    if (year) url += '&year=' + year;

    const data = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });

    if (!data.results || data.results.length === 0) {
      return [{ json: { error: 'No movies found for "' + query + '".' } }];
    }

    let result = 'Movies matching "' + query + '" (' + data.total_results + ' total):\n\n';
    const movies = data.results.slice(0, 5);
    for (const m of movies) {
      result += '**' + m.title + '**';
      if (m.release_date) result += ' (' + m.release_date.substring(0, 4) + ')';
      result += '\n';
      result += 'Rating: ' + formatRating(m.vote_average, m.vote_count) + '\n';
      if (m.overview) result += m.overview.substring(0, 200) + (m.overview.length > 200 ? '...' : '') + '\n';
      result += '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'TMDB search failed: ' + err.message } }];
  }

} else if (action === 'search_tv') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required (TV show title).' } }];

  try {
    const url = 'https://api.themoviedb.org/3/search/tv?query=' + encodeURIComponent(query) + '&language=en-US&page=1';
    const data = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });

    if (!data.results || data.results.length === 0) {
      return [{ json: { error: 'No TV shows found for "' + query + '".' } }];
    }

    let result = 'TV shows matching "' + query + '" (' + data.total_results + ' total):\n\n';
    const shows = data.results.slice(0, 5);
    for (const s of shows) {
      result += '**' + s.name + '**';
      if (s.first_air_date) result += ' (' + s.first_air_date.substring(0, 4) + ')';
      result += '\n';
      result += 'Rating: ' + formatRating(s.vote_average, s.vote_count) + '\n';
      if (s.overview) result += s.overview.substring(0, 200) + (s.overview.length > 200 ? '...' : '') + '\n';
      result += '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'TMDB TV search failed: ' + err.message } }];
  }

} else if (action === 'get_trending') {
  const mediaType = input.media_type || 'all';
  const timeWindow = input.time_window || 'week';

  try {
    const url = 'https://api.themoviedb.org/3/trending/' + mediaType + '/' + timeWindow + '?language=en-US';
    const data = await helpers.httpRequest({ method: 'GET', url, headers: authHeaders });

    if (!data.results || data.results.length === 0) {
      return [{ json: { error: 'No trending results found.' } }];
    }

    let result = 'Trending ' + mediaType + ' this ' + timeWindow + ':\n\n';
    const items = data.results.slice(0, 10);
    for (const item of items) {
      const title = item.title || item.name;
      const date = item.release_date || item.first_air_date || '';
      const type = item.media_type === 'movie' ? 'Movie' : item.media_type === 'tv' ? 'TV' : '';
      result += '- **' + title + '**';
      if (date) result += ' (' + date.substring(0, 4) + ')';
      if (type) result += ' [' + type + ']';
      result += ' — ' + formatRating(item.vote_average, item.vote_count) + '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'TMDB trending failed: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use search_movie, search_tv, or get_trending.' } }];
}
